// RelationalParserInit initializes any static state used to implement RelationalParser. By default the
// static state used to implement the parser is lazily initialized during the first call to
// NewRelationalParser(). You can call this function if you wish to initialize the static state ahead
// of time.
func RelationalParserInit() {
	staticData := &RelationalParserParserStaticData
	staticData.once.Do(relationalparserParserInit)
}

// NewRelationalParser produces a new parser instance for the optional input antlr.TokenStream.
func NewRelationalParser(input antlr.TokenStream) *RelationalParser {
	RelationalParserInit()
	this := new(RelationalParser)
	this.BaseParser = antlr.NewBaseParser(input)
	staticData := &RelationalParserParserStaticData
	this.Interpreter = antlr.NewParserATNSimulator(this, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	this.RuleNames = staticData.RuleNames
	this.LiteralNames = staticData.LiteralNames
	this.SymbolicNames = staticData.SymbolicNames
	this.GrammarFileName = "RelationalParser.g4"

	return this
}

